mapper.select:
/* USE : DataRcvStatusMapper.getDataRcvStatusHdrList */
SELECT  TO_CHAR(TO_DATE(A.LOG_DATE, 'YYYYMMDD'), 'YYYY-MM-DD') AS LOG_DATE
,       TO_CHAR(TO_DATE(A.LOG_DATE, 'YYYYMMDD'), 'DY') AS YOIL
,       TO_CHAR(TO_DATE(A.REG_DT, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS REG_DT
,       NVL(tms.BRANCH_CD, '')  AS BRANCH_CD
,       NVL((SELECT BRANCH_NM FROM TB_HQ_BRANCH_MOMS WHERE HQ_OFFICE_CD = #{hqOfficeCd} AND BRANCH_CD = tms.BRANCH_CD), '') AS BRANCH_NM
,       A.STORE_CD
,       NVL(tms.STORE_NM, '')   AS STORE_NM
,       A.HQ_BRAND_CD
,       NVL(tmsi.MOMS_TEAM, '')     AS MOMS_TEAM
,       NVL(tmsi.MOMS_AC_SHOP, '')  AS MOMS_AC_SHOP
,       A.POS_NO
,       A.LOG_SEQ
,       A.POS_TELEX_ID
FROM    TB_LG_MST_COUNT_LOG_HDR A
,       TB_MS_STORE tms
,       TB_MS_STORE_INFO tmsi
WHERE   A.HQ_OFFICE_CD      = #{hqOfficeCd}
AND     tms.HQ_OFFICE_CD    = A.HQ_OFFICE_CD
AND     tms.STORE_CD        = A.STORE_CD
AND     tmsi.STORE_CD   (+) = tms.STORE_CD
AND     A.LOG_DATE  BETWEEN #{startDate} AND #{endDate}

    AND A.HQ_BRAND_CD       = #{storeHqBrandCd}



        AND A.HQ_BRAND_CD IN

            #{item}




    AND A.STORE_CD IN

        #{item}



    AND tmsi.MOMS_TEAM = #{momsTeam}


    AND tmsi.MOMS_AC_SHOP = #{momsAcShop}


    AND tmsi.MOMS_AREA_FG = #{momsAreaFg}


    AND tmsi.MOMS_COMMERCIAL = #{momsCommercial}


    AND tmsi.MOMS_SHOP_TYPE = #{momsShopType}


    AND tmsi.MOMS_STORE_MANAGE_TYPE = #{momsStoreManageType}


    AND tms.BRANCH_CD = #{branchCd}


    AND tmsi.MOMS_STORE_FG_01 = #{momsStoreFg01}


    AND tmsi.MOMS_STORE_FG_02 = #{momsStoreFg02}


    AND tmsi.MOMS_STORE_FG_03 = #{momsStoreFg03}


    AND tmsi.MOMS_STORE_FG_04 = #{momsStoreFg04}


    AND tmsi.MOMS_STORE_FG_05 = #{momsStoreFg05}

ORDER
BY      A.LOG_DATE
,       A.STORE_CD
,       A.POS_NO
,       A.LOG_SEQ
